package com.zhou;

import com.rabbitmq.client.Channel;
import com.rabbitmq.client.Connection;
import com.rabbitmq.client.ConnectionFactory;
import com.rabbitmq.client.MessageProperties;

import java.io.IOException;
import java.util.concurrent.TimeoutException;

public class RabbitProducer {
    private static final String EXCHANGE_NAME = "exchange_demo";
    private static final String ROUTING_KEY = "routingkey_demo";
    private static final String QUEUE_NAME = "queue_demo";
    private static final String IP_ADDRESS = "127.0.0.1";
    // RabbitMQжңҚеҠЎз«Ҝй»ҳи®Өз«ҜеҸЈдёә5672
    private static final int PORT = 5672;

    public static void main(String[] args) throws IOException, TimeoutException {
        ConnectionFactory factory = new ConnectionFactory();
        factory.setHost(IP_ADDRESS);
        factory.setPort(PORT);
        factory.setUsername("root");
        factory.setPassword("root");

        // еҲӣе»әиҝһжҺҘ
        Connection connection = factory.newConnection();
        // еҲӣе»әдҝЎйҒ“
        Channel channel = connection.createChannel();
        // еҲӣе»әдёҖдёӘtypeдёәdirectпјҢжҢҒд№…еҢ–зҡ„пјҢйқһиҮӘеҠЁеҲ йҷӨзҡ„дәӨжҚўеҷЁ
        channel.exchangeDeclare(EXCHANGE_NAME,"direct",true,false,null);
        // еҲӣе»әдёҖдёӘжҢҒд№…еҢ–пјҢйқһжҺ’д»–зҡ„пјҢйқһиҮӘеҠЁеҲ йҷӨзҡ„йҳҹеҲ—
        channel.queueDeclare(QUEUE_NAME,true,false,false,null);
        // е°ҶдәӨжҚўеҷЁдёҺйҳҹеҲ—йҖҡиҝҮи·Ҝз”ұй”®з»‘е®ҡ
        channel.queueBind(QUEUE_NAME,EXCHANGE_NAME,ROUTING_KEY);
        // еҸ‘йҖҒдёҖжқЎжҢҒд№…еҢ–зҡ„ж¶ҲжҒҜ:hello world
        String message = "hello world";
        channel.basicPublish(EXCHANGE_NAME,ROUTING_KEY,
                MessageProperties.PERSISTENT_TEXT_PLAIN,message.getBytes());

        // е…ій—ӯиө„жәҗ
        channel.close();
        connection.close();


    }
}

