protected void prepareRefresh() {
    // Switch to active.
    this.startupDate = System.currentTimeMillis();
    // еҺҹеӯҗbooleanеҖјпјҢз”ЁжқҘж ҮиҜҶиҜҘcontextжІЎжңүиў«е…ій—ӯ
